const hoje = new Date();
const ontem = new Date(hoje);
ontem.setDate(ontem.getDate() - 1);

const fmt = (d) => d.toISOString().split('T')[0];

const diaSemana = hoje.getDay();
const diaDoMes = hoje.getDate();

// Semana atual (segunda a domingo)
const inicioSemana = new Date(hoje);
inicioSemana.setDate(hoje.getDate() - ((diaSemana + 6) % 7));
const inicioSemanaPassada = new Date(inicioSemana);
inicioSemanaPassada.setDate(inicioSemanaPassada.getDate() - 7);
const fimSemanaPassada = new Date(inicioSemana);
fimSemanaPassada.setDate(fimSemanaPassada.getDate() - 1);

// Mês atual e anterior
const inicioMes = new Date(hoje.getFullYear(), hoje.getMonth(), 1);
const inicioMesPassado = new Date(hoje.getFullYear(), hoje.getMonth() - 1, 1);
const fimMesPassado = new Date(hoje.getFullYear(), hoje.getMonth(), 0);

const tiposRelatorio = ['diario'];
if (diaSemana === 1) tiposRelatorio.push('semanal');
if (diaDoMes === 1) tiposRelatorio.push('mensal');

return [{
  json: {
    tipos_relatorio: tiposRelatorio,
    is_semanal: diaSemana === 1,
    is_mensal: diaDoMes === 1,
    hoje: fmt(hoje),
    ontem: fmt(ontem),
    inicio_semana_atual: fmt(inicioSemana),
    inicio_semana_passada: fmt(inicioSemanaPassada),
    fim_semana_passada: fmt(fimSemanaPassada),
    inicio_mes_atual: fmt(inicioMes),
    inicio_mes_passado: fmt(inicioMesPassado),
    fim_mes_passado: fmt(fimMesPassado),
    dia_semana_nome: ['Domingo','Segunda','Terça','Quarta','Quinta','Sexta','Sábado'][diaSemana],
    mes_nome: ['Janeiro','Fevereiro','Março','Abril','Maio','Junho','Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'][hoje.getMonth()]
  }
}];

