// Pegar a análise do AI Agent
const analiseRaw = $input.first().json.output || $input.first().json.text || '{}';
let analise;
try {
  const cleaned = analiseRaw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  analise = JSON.parse(cleaned);
} catch(e) {
  analise = {
    resumo_executivo: analiseRaw,
    kpis: {}, insights: [], alertas: [], recomendacoes: [],
    analise_semanal: null, analise_mensal: null
  };
}

// ⬇️ AQUI É A MUDANÇA: era 'Buscar Todos os Dados', agora é 'Consolidar Dados'
const dados = $('Consolidar Dados').first().json;
const p = dados.periodos;

// Helper: gerar URL de gráfico QuickChart.io
const chart = (config) => {
  const encoded = encodeURIComponent(JSON.stringify(config));
  return `https://quickchart.io/chart?c=${encoded}&w=540&h=300&bkg=white`;
};

const kpi = analise.kpis || {};

// Gráfico 1: Leads Hoje vs Ontem
const chartLeads = chart({
  type: 'bar',
  data: {
    labels: ['Ontem', 'Hoje'],
    datasets: [{
      label: 'Novos Leads',
      data: [kpi.leads_ontem || 0, kpi.leads_hoje || 0],
      backgroundColor: ['#94a3b8', '#6366f1']
    }]
  },
  options: {
    plugins: { title: { display: true, text: 'Leads: Hoje vs Ontem' }},
    scales: { y: { beginAtZero: true }}
  }
});

// Gráfico 2: Vendas Hoje vs Ontem
const chartVendas = chart({
  type: 'bar',
  data: {
    labels: ['Ontem', 'Hoje'],
    datasets: [{
      label: 'Vendas',
      data: [kpi.vendas_ontem || 0, kpi.vendas_hoje || 0],
      backgroundColor: ['#94a3b8', '#10b981']
    }]
  },
  options: {
    plugins: { title: { display: true, text: 'Vendas: Hoje vs Ontem' }},
    scales: { y: { beginAtZero: true }}
  }
});

// Gráfico 3: Distribuição por Destino
const destinos = dados.reports_mes_atual?.breakdown?.destinos || {};
const chartDestinos = chart({
  type: 'doughnut',
  data: {
    labels: Object.keys(destinos).slice(0, 6),
    datasets: [{
      data: Object.values(destinos).slice(0, 6),
      backgroundColor: ['#6366f1','#10b981','#f59e0b','#ef4444','#8b5cf6','#06b6d4']
    }]
  },
  options: {
    plugins: { title: { display: true, text: `Destinos - ${p.mes_nome}` }}
  }
});

// Gráfico 4: Evolução do mês
const dashChart = dados.reports_mes_atual?.chart || {};
const chartEvolucao = chart({
  type: 'line',
  data: {
    labels: (dashChart.labels || []).map(l => l.slice(5)),
    datasets: [
      { label: 'Vendas', data: dashChart.vendas || [], borderColor: '#10b981', fill: false },
      { label: 'Perdas', data: dashChart.perdas || [], borderColor: '#ef4444', fill: false },
      { label: 'Em Negociação', data: dashChart.em_negociacao || [], borderColor: '#f59e0b', fill: false }
    ]
  },
  options: {
    plugins: { title: { display: true, text: `Evolução ${p.mes_nome}` }},
    scales: { y: { beginAtZero: true }}
  }
});

// Montar HTML
const varColor = (val) => {
  if (!val) return '#64748b';
  return val.startsWith('+') ? '#10b981' : val.startsWith('-') ? '#ef4444' : '#64748b';
};

let html = `
<div style="font-family:'Segoe UI',Arial,sans-serif;max-width:600px;margin:0 auto;background:#f8fafc;padding:20px;">

  <div style="background:linear-gradient(135deg,#6366f1,#8b5cf6);padding:24px;border-radius:12px;color:white;text-align:center;">
    <h1 style="margin:0;font-size:22px;">📊 Relatório ${p.dia_semana_nome} — ${p.hoje}</h1>
    <p style="margin:8px 0 0;opacity:0.9;font-size:14px;">Brasileiros no Atacama</p>
  </div>

  <div style="background:white;border-radius:12px;padding:20px;margin-top:16px;border:1px solid #e2e8f0;">
    <h2 style="color:#1e293b;font-size:16px;margin:0 0 12px;">📝 Resumo Executivo</h2>
    <p style="color:#475569;font-size:14px;line-height:1.6;margin:0;">${analise.resumo_executivo || 'Sem dados suficientes para análise.'}</p>
  </div>

  <div style="display:flex;gap:12px;margin-top:16px;flex-wrap:wrap;">
    <div style="flex:1;min-width:120px;background:white;border-radius:12px;padding:16px;text-align:center;border:1px solid #e2e8f0;">
      <div style="font-size:24px;font-weight:700;color:#6366f1;">${kpi.leads_hoje ?? '—'}</div>
      <div style="font-size:12px;color:#64748b;">Leads Hoje</div>
      <div style="font-size:12px;font-weight:600;color:${varColor(kpi.variacao_leads)};">${kpi.variacao_leads || ''}</div>
    </div>
    <div style="flex:1;min-width:120px;background:white;border-radius:12px;padding:16px;text-align:center;border:1px solid #e2e8f0;">
      <div style="font-size:24px;font-weight:700;color:#10b981;">${kpi.vendas_hoje ?? '—'}</div>
      <div style="font-size:12px;color:#64748b;">Vendas Hoje</div>
      <div style="font-size:12px;font-weight:600;color:${varColor(kpi.variacao_vendas)};">${kpi.variacao_vendas || ''}</div>
    </div>
    <div style="flex:1;min-width:120px;background:white;border-radius:12px;padding:16px;text-align:center;border:1px solid #e2e8f0;">
      <div style="font-size:24px;font-weight:700;color:#f59e0b;">${kpi.taxa_conversao || '—'}</div>
      <div style="font-size:12px;color:#64748b;">Conversão</div>
    </div>
    <div style="flex:1;min-width:120px;background:white;border-radius:12px;padding:16px;text-align:center;border:1px solid #e2e8f0;">
      <div style="font-size:24px;font-weight:700;color:#ef4444;">${kpi.tarefas_pendentes ?? '—'}</div>
      <div style="font-size:12px;color:#64748b;">Tarefas Pendentes</div>
    </div>
  </div>

  <div style="background:white;border-radius:12px;padding:20px;margin-top:16px;border:1px solid #e2e8f0;">
    <h2 style="color:#1e293b;font-size:16px;margin:0 0 12px;">📊 Comparativo Diário</h2>
    <img src="${chartLeads}" alt="Leads" style="width:100%;border-radius:8px;margin-bottom:12px;" />
    <img src="${chartVendas}" alt="Vendas" style="width:100%;border-radius:8px;" />
  </div>

  <div style="background:white;border-radius:12px;padding:20px;margin-top:16px;border:1px solid #e2e8f0;">
    <h2 style="color:#1e293b;font-size:16px;margin:0 0 12px;">🗺️ Destinos & Evolução</h2>
    <img src="${chartDestinos}" alt="Destinos" style="width:100%;border-radius:8px;margin-bottom:12px;" />
    <img src="${chartEvolucao}" alt="Evolução" style="width:100%;border-radius:8px;" />
  </div>`;

if (analise.insights?.length) {
  html += `<div style="background:white;border-radius:12px;padding:20px;margin-top:16px;border:1px solid #e2e8f0;">
    <h2 style="color:#1e293b;font-size:16px;margin:0 0 12px;">💡 Insights</h2>
    <ul style="color:#475569;font-size:14px;padding-left:20px;margin:0;">
      ${analise.insights.map(i => `<li style="margin-bottom:8px;">${i}</li>`).join('')}
    </ul>
  </div>`;
}

if (analise.alertas?.length) {
  html += `<div style="background:#fef2f2;border-radius:12px;padding:20px;margin-top:16px;border:1px solid #fecaca;">
    <h2 style="color:#dc2626;font-size:16px;margin:0 0 12px;">🚨 Alertas</h2>
    <ul style="color:#991b1b;font-size:14px;padding-left:20px;margin:0;">
      ${analise.alertas.map(a => `<li style="margin-bottom:8px;">${a}</li>`).join('')}
    </ul>
  </div>`;
}

if (analise.recomendacoes?.length) {
  html += `<div style="background:#f0fdf4;border-radius:12px;padding:20px;margin-top:16px;border:1px solid #bbf7d0;">
    <h2 style="color:#16a34a;font-size:16px;margin:0 0 12px;">✅ Recomendações</h2>
    <ul style="color:#166534;font-size:14px;padding-left:20px;margin:0;">
      ${analise.recomendacoes.map(r => `<li style="margin-bottom:8px;">${r}</li>`).join('')}
    </ul>
  </div>`;
}

if (analise.analise_semanal) {
  html += `<div style="background:#eff6ff;border-radius:12px;padding:20px;margin-top:16px;border:1px solid #bfdbfe;">
    <h2 style="color:#1d4ed8;font-size:16px;margin:0 0 12px;">📆 Análise Semanal</h2>
    <p style="color:#1e40af;font-size:14px;line-height:1.6;margin:0;">${typeof analise.analise_semanal === 'string' ? analise.analise_semanal : JSON.stringify(analise.analise_semanal)}</p>
  </div>`;
}

if (analise.analise_mensal) {
  html += `<div style="background:#fdf4ff;border-radius:12px;padding:20px;margin-top:16px;border:1px solid #e9d5ff;">
    <h2 style="color:#7e22ce;font-size:16px;margin:0 0 12px;">📅 Análise Mensal</h2>
    <p style="color:#6b21a8;font-size:14px;line-height:1.6;margin:0;">${typeof analise.analise_mensal === 'string' ? analise.analise_mensal : JSON.stringify(analise.analise_mensal)}</p>
  </div>`;
}

html += `
  <div style="text-align:center;margin-top:20px;padding:16px;color:#94a3b8;font-size:12px;">
    Gerado automaticamente por IA — ${p.hoje} às 07:00<br>
    Brasileiros no Atacama • CRM Analytics
  </div>
</div>`;

let assunto = `📊 Relatório Diário — ${p.hoje}`;
if (p.is_semanal) assunto = `📆 Relatório Semanal + Diário — ${p.hoje}`;
if (p.is_mensal) assunto = `📅 Relatório Mensal + Diário — ${p.hoje}`;

return [{ json: { assunto, html, analise } }];

const p = $('Code in JavaScript').first().json;
const dashHoje = $('Dashboard Hoje').first().json;
const dashOntem = $('Dashboard Ontem').first().json;
const reports = $('Reports Mês').first().json;

return [{
  json: {
    periodos: p,
    dashboard_hoje: dashHoje,
    dashboard_ontem: dashOntem,
    reports_mes_atual: reports
  }
}];
